import{_ as t,o,c as n,ae as s}from"./chunks/framework.Czhw_PXq.js";const d=JSON.parse('{"title":"📈 股票估值与收益：五大核心财务指标指南","description":"","frontmatter":{},"headers":[],"relativePath":"quant/v5-record.md","filePath":"quant/v5-record.md"}'),l={name:"quant/v5-record.md"};function a(g,r,e,i,p,u){return o(),n("div",null,[...r[0]||(r[0]=[s('<h1 id="📈-股票估值与收益-五大核心财务指标指南" tabindex="-1">📈 股票估值与收益：五大核心财务指标指南 <a class="header-anchor" href="#📈-股票估值与收益-五大核心财务指标指南" aria-label="Permalink to &quot;📈 股票估值与收益：五大核心财务指标指南&quot;">​</a></h1><h2 id="_1-市盈率-pe-——-回本年限测算器" tabindex="-1">1. 市盈率 (PE) —— “回本年限测算器” <a class="header-anchor" href="#_1-市盈率-pe-——-回本年限测算器" aria-label="Permalink to &quot;1. 市盈率 (PE) —— “回本年限测算器”&quot;">​</a></h2><p><strong>核心公式</strong>：$PE = \\frac{P}{E}$ （市值 $\\div$ 净利润）</p><p><strong>大白话理解</strong>：反映我们愿意为获取公司 1 元的净利润付出多少代价。</p><blockquote><p><strong>💡 形象比喻</strong>： 你花 100 万买了一台“自动提款机”，它每年吐出 10 万块钱。这时的 PE 就是 10。这意味着，如果你不把这台机器卖掉，需要 <strong>10 年</strong>时间，吐出来的钱才够抵消你买机器的成本。</p></blockquote><p><strong>三大分类</strong>：</p><ul><li><strong>静态市盈率</strong>：看“后视镜”（用上一个年度的净利润计算）。</li><li><strong>滚动市盈率 (TTM)</strong>：看“当下”（用最近 4 个季度财报的净利润计算，最常用、最客观）。</li><li><strong>动态市盈率</strong>：看“未来”（用预估的下一年度净利润计算，带有预测水分）。</li></ul><p><strong>实战例子</strong>：如果一家公司一年赚 100 亿元净利润，它的市盈率是 10，其市值就是 1000 亿元。这意味着，你愿意为这家公司 1 元的盈利付出 10 元。假设公司赚钱能力不变，你买下它相当于 10 年回本。</p><ul><li><strong>✅ 适用场景</strong>：流通性好、盈利稳定的品种（如大消费、医药等白马股）。</li><li><strong>⚠️ 避雷指南 / 坑点</strong>： <ul><li><strong>周期性行业</strong>（如养猪、钢铁、海运、煤炭）：这些行业盈利忽高忽低。猪肉贵时盈利爆发，PE 显得极低（比如 3 倍），但这往往是盈利顶点，随后可能转亏。<strong>避雷口诀：强周期行业，低 PE 往往是卖点，高 PE 反而是买点。</strong></li><li><strong>亏损企业</strong>：当净利润 $E$ 为负数时，PE 失去意义。</li></ul></li></ul><hr><h2 id="_2-盈利收益率-——-买断公司的年化利息" tabindex="-1">2. 盈利收益率 —— “买断公司的年化利息” <a class="header-anchor" href="#_2-盈利收益率-——-买断公司的年化利息" aria-label="Permalink to &quot;2. 盈利收益率 —— “买断公司的年化利息”&quot;">​</a></h2><p><strong>核心公式</strong>：$盈利收益率 = \\frac{E}{P}$ （净利润 $\\div$ 市值，即市盈率的倒数）</p><p><strong>大白话理解</strong>：假设我们把一家公司全部买下来，它一年的盈利能够带给我们的收益率。一般来说，盈利收益率越高，代表公司估值越低，越有可能被低估（物美价廉）。</p><p><strong>实战例子</strong>：市盈率是 10 倍的公司，盈利收益率就是 10%（1 $\\div$ 10）。这就好比你把钱存在“这家公司”这个银行里，每年的存款利息是 10%。</p><ul><li><strong>✅ 适用场景</strong>：与市盈率一样，要求流通性好、盈利稳定。</li></ul><hr><h2 id="_3-市净率-pb-——-买下公司家底的溢价" tabindex="-1">3. 市净率 (PB) —— “买下公司家底的溢价” <a class="header-anchor" href="#_3-市净率-pb-——-买下公司家底的溢价" aria-label="Permalink to &quot;3. 市净率 (PB) —— “买下公司家底的溢价”&quot;">​</a></h2><p><strong>核心公式</strong>：$PB = \\frac{市值}{净资产}$ （或 股价 $\\div$ 每股净资产）</p><p><strong>大白话理解</strong>：代表你愿意花多少钱去买公司 1 元的“真实家底”（总资产减去总负债）。如果市净率小于 1（即“破净”），说明你买这家公司的价格，比它把设备全卖废铁的底价还要便宜。</p><blockquote><p><strong>💡 形象比喻</strong>： 之前那台“提款机”外壳是金子做的，里面的零件也值钱。就算它不吐钱了，拆开卖废铁也能卖 50 万。如果你花 60 万买它，溢价率 PB 就是 1.2。</p></blockquote><p><strong>实战例子</strong>：一家公司的净资产（家底）是 100 亿，当前市值是 200 亿，市净率就是 2。这意味着你花了 2 块钱的溢价，买到了公司账面价值 1 块钱的资产。</p><ul><li><strong>✅ 适用场景</strong>：资产保值性强、流动性好的重资产行业（如银行、券商、基建）。</li><li><strong>⚠️ 避雷指南 / 坑点</strong>： <ul><li><strong>轻资产/高科技行业</strong>（如软件、游戏、互联网、咨询）：这些公司的值钱之处在于员工的大脑和品牌，账面上的办公桌椅（净资产）根本不值钱。对于这类公司，PB 哪怕是 10 甚至 100，参考意义也不大。</li><li><strong>资产质量陷阱</strong>：注意资产的“质量”。如果一个公司的净资产全是卖不掉的库存或收不回来的欠款，那 PB 再低也是“假便宜”。</li></ul></li></ul><hr><h2 id="_4-净资产收益率-roe-——-资本的赚钱效率" tabindex="-1">4. 净资产收益率 (ROE) —— “资本的赚钱效率” <a class="header-anchor" href="#_4-净资产收益率-roe-——-资本的赚钱效率" aria-label="Permalink to &quot;4. 净资产收益率 (ROE) —— “资本的赚钱效率”&quot;">​</a></h2><p><strong>核心公式</strong>：$ROE = \\frac{净利润}{净资产} \\times 100%$</p><p><strong>大白话理解</strong>：公司用股东给的“本钱”赚钱的效率。这是股神巴菲特最看重的终极指标。长期来看，投资者持股的年化回报率往往无限接近于公司的 ROE。一般认为，能长期保持 ROE &gt; 15% 的公司，通常具备很深的护城河。</p><blockquote><p><strong>💡 形象比喻</strong>： 你有两只母鸡（公司资产），甲鸡吃 1 斤粮产 10 个蛋，乙鸡吃 1 斤粮产 20 个蛋。乙鸡的 ROE 更高，它是一只赚钱效率更高的优秀母鸡。</p></blockquote><p><strong>实战例子</strong>：你拿 100 万本金开了一家奶茶店（净资产），年底纯赚了 20 万（净利润），那这家店的 ROE 就是 20%。</p><ul><li><strong>⚠️ 避雷指南 / 坑点</strong>： <ul><li><strong>高杠杆陷阱</strong>：有的公司 ROE 很高，是因为借了大量的钱（负债）。这就像为了让鸡多产蛋给它打了兴奋剂，虽然短期产量高，但风险极大。<strong>引申思考：看 ROE 时，一定要同时看资产负债率。</strong></li></ul></li></ul><hr><h2 id="_5-股息率-——-落袋为安的现金收租" tabindex="-1">5. 股息率 —— “落袋为安的现金收租” <a class="header-anchor" href="#_5-股息率-——-落袋为安的现金收租" aria-label="Permalink to &quot;5. 股息率 —— “落袋为安的现金收租”&quot;">​</a></h2><p><strong>核心公式</strong>：$股息率 = \\frac{年度总派息额}{公司总市值} \\times 100%$</p><p><strong>大白话理解</strong>：公司赚了钱之后，真金白银地把现金分发给股东的收益率比例。不需要靠股价上涨也能赚钱，是实打实的现金流。</p><blockquote><p><strong>💡 形象比喻</strong>： 你买了一套房，房价涨跌是“市值”，而每年收到的租金就是“股息”。股息率就相当于买房的<strong>租金回报率</strong>。</p></blockquote><p><strong>实战例子</strong>：你花 100 万买了一家公司的股票，今年这家公司往你的股票账户里打了 5 万块钱现金分红，你的股息率就是 5%。</p><ul><li><strong>✅ 适用场景</strong>：处于成熟期、扩张意愿低但现金流极其充沛的“现金奶牛”型公司（如高速公路、水电煤气、部分大型银行）。</li><li><strong>⚠️ 避雷指南 / 坑点</strong>： <ul><li><strong>“铁公鸡”陷阱</strong>：有的公司账上很有钱，但从不给股东分红。</li><li><strong>“假大方”陷阱</strong>：有的公司为了维持高分红的表象，甚至不惜借钱分红，这种模式不可持续，遇到这类情况需要高度警惕。</li></ul></li></ul>',36)])])}const h=t(l,[["render",a]]);export{d as __pageData,h as default};
